class Solution:
    def prisonAfterNDays(self, cells, n):
        def step(c):
            return [0] + [1 if c[i - 1] == c[i + 1] else 0 for i in range(1, 7)] + [0]
        seen = {}
        cur = list(cells)
        day = 0
        while day < n:
            key = tuple(cur)
            if key in seen:
                period = day - seen[key]
                rem = (n - day) % period
                for _ in range(rem):
                    cur = step(cur)
                return cur
            seen[key] = day
            cur = step(cur)
            day += 1
        return cur

