var prisonAfterNDays = function(cells, n) {
    const step = (c) => {
        const r = new Array(8).fill(0);
        for (let i = 1; i < 7; i++) r[i] = c[i - 1] === c[i + 1] ? 1 : 0;
        return r;
    };
    n = (n - 1) % 14 + 1;
    let cur = cells.slice();
    for (let d = 0; d < n; d++) cur = step(cur);
    return cur;
};
